(function(){const clockEl=document.getElementById("displaybus-clock");const rowsEl=document.getElementById("displaybus-rows");const emptyEl=document.getElementById("displaybus-empty");const emptyReasonEl=document.getElementById("displaybus-empty-reason");const footnoteEl=document.getElementById("displaybus-footnote");const pageHintEl=document.getElementById("displaybus-page-hint");let lastData=null;let busPageCtl=null;const PAGE_SWITCH_MS=12000;const POLL_MS=30000;function getParisNowMinutes(){const s=new Date().toLocaleString("sv-SE",{timeZone:"Europe/Paris"});const timePart=(s.split(" ")[1]||"0:0:0").slice(0,5);const[h,m]=timePart.split(":").map((x)=>parseInt(x,10)||0);return h*60+m;}
function isNowInBusSlots(slots){if(!slots||!slots.length)return true;const nowMin=getParisNowMinutes();for(const slot of slots){try{const[sh,sm]=(slot.start||"00:00").split(":").map(Number);const[eh,em]=(slot.end||"23:59").split(":").map(Number);const a=sh*60+sm;const b=eh*60+em;if(nowMin>=a&&nowMin<=b)return true;}catch(e){}}
return false;}
function isBusForceFromPublic(pub){if(!pub.bus_force_display)return false;const until=pub.bus_force_display_until;if(!until)return true;const u=new Date(until);if(Number.isNaN(u.getTime()))return true;return Date.now()<u.getTime();}
function showEmpty(reason){if(busPageCtl){busPageCtl.destroy();busPageCtl=null;}
if(rowsEl){rowsEl.innerHTML='<div id="displaybus-viewport" class="bus-dep-viewport"></div>';rowsEl.style.display="none";}
if(emptyEl)emptyEl.classList.remove("hidden");if(footnoteEl)footnoteEl.textContent="";if(pageHintEl){pageHintEl.hidden=true;pageHintEl.textContent="";}
if(emptyReasonEl){const labels={outside_schedule:"Hors créneau horaire.",no_departures_in_window:"Aucun départ dans la fenêtre affichée.",no_service_today:"Pas de service ce jour.",gtfs_not_loaded:"Données non chargées.",disabled:"Affichage bus désactivé.","Erreur réseau":"Impossible de joindre le serveur.",};const msg=reason?labels[reason]||reason:"";emptyReasonEl.textContent=msg;}}
function showData(data){if(emptyEl)emptyEl.classList.add("hidden");if(rowsEl)rowsEl.style.display="";const deps=(data.departures||[]).slice();if(busPageCtl){busPageCtl.destroy();busPageCtl=null;}
const theory=data.source==="gtfs_static"||data.source==="test";if(footnoteEl){footnoteEl.textContent=theory?"Horaires théoriques (GTFS)":"";}
const viewport=document.getElementById("displaybus-viewport");if(viewport&&typeof busBoardPagesMount==="function"){busPageCtl=busBoardPagesMount(viewport,deps,{pageSwitchMs:PAGE_SWITCH_MS,pageHintEl:pageHintEl,});}else if(rowsEl&&typeof busBoardTableHtml==="function"){rowsEl.innerHTML=busBoardTableHtml(deps,{showHead:true});rowsEl.querySelectorAll(".bus-scroll-text").forEach((el)=>{if(el.scrollWidth>el.parentElement.offsetWidth)el.classList.add("bus-scroll-animate");});}}
function tickClock(){if(!clockEl)return;const now=new Date();const t=now.toLocaleTimeString("fr-FR",{hour:"2-digit",minute:"2-digit",second:"2-digit",hour12:false,timeZone:"Europe/Paris",});clockEl.textContent=t;clockEl.setAttribute("datetime",now.toISOString());}
async function refresh(){try{if(typeof DisplayAnnouncements!=="undefined"&&DisplayAnnouncements.isPriorityActive()){return;}
const pubRes=await fetch("/api/settings/public");const pub=await pubRes.json();if(!pub.feature_bus_enabled){lastData={available:false};showEmpty("disabled");return;}
const force=isBusForceFromPublic(pub);const slots=pub.bus_schedule||[];const restrict=pub.bus_restrict_to_schedule===true;if(restrict&&!force&&!isNowInBusSlots(slots)){lastData={available:false,reason:"outside_schedule"};showEmpty("outside_schedule");if(typeof busLogPayload==="function"){busLogPayload({available:false,reason:"outside_schedule"},"displaybus",{client_gate:"hors créneau (bus_restrict_to_schedule=true)",force:force,in_slots:isNowInBusSlots(slots),});}
return;}
const busUrl=typeof busDisplayApiUrl==="function"?busDisplayApiUrl("/api/display/bus"):"/api/display/bus";const res=await fetch(busUrl);const data=await res.json();lastData=data;if(typeof busLogPayload==="function"){busLogPayload(data,"displaybus",{bus_restrict_to_schedule:restrict,client_schedule_gate:"non appliqué (aligné serveur si restrict=false)",});}
if(data.available&&data.departures?.length){showData(data);}else{showEmpty(data.reason||"");}}catch(e){lastData={available:false};showEmpty("Erreur réseau");}}
function startAnnouncementsPolling(){if(typeof DisplayAnnouncements==="undefined")return;DisplayAnnouncements.setModeProvider(function(){return"normal";});setInterval(function(){DisplayAnnouncements.fetchPriorityAnnouncement().then(function(){if(DisplayAnnouncements.isPriorityActive())return;DisplayAnnouncements.fetchAnnouncements();});},4000);}
tickClock();setInterval(tickClock,1000);startAnnouncementsPolling();(async function init(){if(typeof DisplayAnnouncements!=="undefined"){DisplayAnnouncements.setModeProvider(function(){return"normal";});await DisplayAnnouncements.fetchPriorityAnnouncement();if(DisplayAnnouncements.isPriorityActive()){return;}
await DisplayAnnouncements.fetchAnnouncements();}
refresh();setInterval(refresh,POLL_MS);})();})();